package main

import (
	"fmt"
	"time"

	"lru"
)

const (
	capacity   = 10_000
	totalOps   = 1_000_000
	keyspace   = 20_000
	lcgMul     = 6364136223846793005
	lcgInc     = 1442695040888963407
	initialSt  = 42
)

// runPass executes one full pass of the deterministic workload against c,
// starting from the given LCG state. It returns the final LCG state and the
// wrapping-u64 checksum of all successful-get values.
func runPass(c *lru.LRUCache, state uint64) (uint64, uint64) {
	var checksum uint64
	for i := 0; i < totalOps; i++ {
		state = lcgMul*state + lcgInc // wrapping uint64 arithmetic
		key := int64((state >> 33) % keyspace)
		if state&1 == 0 {
			if v, ok := c.Get(key); ok {
				checksum += uint64(v) // wrapping u64 sum
			}
		} else {
			c.Put(key, key)
		}
	}
	return state, checksum
}

func main() {
	// Warm-up pass (not timed). Fresh cache, LCG starts from the seed.
	c := lru.NewLRUCache(capacity)
	runPass(c, uint64(initialSt))

	// Timed pass: reuse the warmed cache, restart the LCG from the seed so the
	// checksum is deterministic and identical across all language implementations.
	start := time.Now()
	_, checksum := runPass(c, uint64(initialSt))
	elapsed := time.Since(start).Seconds()

	opsPerSec := float64(totalOps) / elapsed

	fmt.Printf("total_ops:   %d\n", totalOps)
	fmt.Printf("elapsed_s:   %.6f\n", elapsed)
	fmt.Printf("ops_per_sec: %.0f\n", opsPerSec)
	fmt.Printf("final_size:  %d\n", c.Len())
	fmt.Printf("checksum:    %d\n", checksum)
}

// bench.cpp — exact benchmark from SPEC.md.
#include "lru.hpp"

#include <chrono>
#include <cstdint>
#include <cstdio>

int main() {
    constexpr std::size_t   CAPACITY = 10000;
    constexpr std::uint64_t TOTAL_OPS = 1000000;
    constexpr std::uint64_t KEYSPACE = 20000;

    // LCG constants (wrapping unsigned 64-bit).
    constexpr std::uint64_t A = 6364136223846793005ULL;
    constexpr std::uint64_t C = 1442695040888963407ULL;

    auto run_pass = [&](bool timed) -> std::pair<std::uint64_t, double> {
        LRUCache cache(CAPACITY);
        std::uint64_t state = 42;
        std::uint64_t checksum = 0; // wrapping u64 sum of successful-get values.

        auto start = std::chrono::steady_clock::now();
        for (std::uint64_t i = 0; i < TOTAL_OPS; ++i) {
            state = A * state + C;                       // wrapping
            std::uint64_t key = (state >> 33) % KEYSPACE;
            if ((state & 1ULL) == 0) {
                auto v = cache.get(static_cast<std::int64_t>(key));
                if (v.has_value()) {
                    checksum += static_cast<std::uint64_t>(v.value()); // wrapping
                }
            } else {
                cache.put(static_cast<std::int64_t>(key),
                          static_cast<std::int64_t>(key));
            }
        }
        auto end = std::chrono::steady_clock::now();
        double elapsed = std::chrono::duration<double>(end - start).count();
        (void)timed;
        // Return checksum and elapsed; also stash final size via static hack-free path.
        // We need final size too; recompute below by returning through struct-like pair
        // is insufficient, so print inside for timed pass instead.
        if (timed) {
            std::printf("final cache size: %zu\n", cache.len());
        }
        return {checksum, elapsed};
    };

    // Warm-up pass (not timed).
    run_pass(false);

    // Timed pass.
    auto [checksum, elapsed] = run_pass(true);

    double ops_per_sec = static_cast<double>(TOTAL_OPS) / elapsed;

    std::printf("total ops:   %llu\n", static_cast<unsigned long long>(TOTAL_OPS));
    std::printf("elapsed sec: %.6f\n", elapsed);
    std::printf("ops/sec:     %.0f\n", ops_per_sec);
    std::printf("checksum:    %llu\n", static_cast<unsigned long long>(checksum));

    return 0;
}

