// lru.hpp — header-only LRU cache (C++17)
// Key/value: int64_t. O(1) average get/put via unordered_map + list.
#ifndef LRU_HPP
#define LRU_HPP

#include <cstdint>
#include <list>
#include <optional>
#include <unordered_map>
#include <stdexcept>
#include <utility>

class LRUCache {
public:
    using key_type   = std::int64_t;
    using value_type = std::int64_t;

    explicit LRUCache(std::size_t capacity) : capacity_(capacity) {
        if (capacity_ == 0) {
            throw std::invalid_argument("LRUCache capacity must be > 0");
        }
    }

    // Return value and mark most-recently-used; std::nullopt if absent.
    std::optional<value_type> get(key_type key) {
        auto it = map_.find(key);
        if (it == map_.end()) {
            return std::nullopt;
        }
        // Move node to front (most-recently-used) in O(1).
        order_.splice(order_.begin(), order_, it->second);
        return it->second->second;
    }

    // Insert/update; mark most-recently-used. Evict LRU first if a NEW key
    // would exceed capacity. Updating an existing key does NOT evict.
    void put(key_type key, value_type value) {
        auto it = map_.find(key);
        if (it != map_.end()) {
            // Update existing: refresh recency, no eviction.
            it->second->second = value;
            order_.splice(order_.begin(), order_, it->second);
            return;
        }
        // New key: evict LRU first if at capacity.
        if (map_.size() >= capacity_) {
            const auto& lru = order_.back();
            map_.erase(lru.first);
            order_.pop_back();
        }
        order_.emplace_front(key, value);
        map_.emplace(key, order_.begin());
    }

    std::size_t len() const noexcept { return map_.size(); }

    std::size_t capacity() const noexcept { return capacity_; }

private:
    using list_type = std::list<std::pair<key_type, value_type>>;

    std::size_t capacity_;
    list_type   order_;  // front = MRU, back = LRU
    std::unordered_map<key_type, typename list_type::iterator> map_;
};

#endif // LRU_HPP

//! O(1) LRU cache: HashMap + arena-based doubly linked list.
//!
//! Key/value are i64. The doubly linked list is implemented over a `Vec`
//! arena so we stay 100% safe (no raw pointers). Node "pointers" are
//! `Option<usize>` indices into the arena. Freed slots are recycled via a
//! free list so the arena size stays bounded by capacity.

use std::collections::HashMap;

struct Node {
    key: i64,
    value: i64,
    prev: Option<usize>,
    next: Option<usize>,
}

pub struct LRUCache {
    capacity: usize,
    map: HashMap<i64, usize>,
    arena: Vec<Node>,
    free: Vec<usize>,
    head: Option<usize>, // most-recently-used
    tail: Option<usize>, // least-recently-used
    size: usize,
}

impl LRUCache {
    /// Create a cache with fixed `capacity` (> 0).
    pub fn new(capacity: usize) -> Self {
        assert!(capacity > 0, "capacity must be > 0");
        LRUCache {
            capacity,
            map: HashMap::with_capacity(capacity),
            arena: Vec::with_capacity(capacity),
            free: Vec::new(),
            head: None,
            tail: None,
            size: 0,
        }
    }

    #[inline]
    pub fn len(&self) -> usize {
        self.size
    }

    #[inline]
    pub fn is_empty(&self) -> bool {
        self.size == 0
    }

    /// Detach node `idx` from the linked list (does not touch map/arena slot).
    #[inline]
    fn detach(&mut self, idx: usize) {
        let (prev, next) = {
            let n = &self.arena[idx];
            (n.prev, n.next)
        };
        match prev {
            Some(p) => self.arena[p].next = next,
            None => self.head = next, // idx was head
        }
        match next {
            Some(nx) => self.arena[nx].prev = prev,
            None => self.tail = prev, // idx was tail
        }
    }

    /// Push node `idx` to the front (most-recently-used).
    #[inline]
    fn push_front(&mut self, idx: usize) {
        let old_head = self.head;
        {
            let n = &mut self.arena[idx];
            n.prev = None;
            n.next = old_head;
        }
        match old_head {
            Some(h) => self.arena[h].prev = Some(idx),
            None => self.tail = Some(idx), // list was empty
        }
        self.head = Some(idx);
    }

    /// Move an existing node to the front.
    #[inline]
    fn move_to_front(&mut self, idx: usize) {
        if self.head == Some(idx) {
            return;
        }
        self.detach(idx);
        self.push_front(idx);
    }

    /// Return value for `key` and mark it most-recently-used.
    pub fn get(&mut self, key: i64) -> Option<i64> {
        if let Some(&idx) = self.map.get(&key) {
            self.move_to_front(idx);
            Some(self.arena[idx].value)
        } else {
            None
        }
    }

    /// Insert or update `key` -> `value`, marking it most-recently-used.
    /// Evicts the LRU entry first if inserting a new key exceeds capacity.
    pub fn put(&mut self, key: i64, value: i64) {
        if let Some(&idx) = self.map.get(&key) {
            // Update existing: no eviction.
            self.arena[idx].value = value;
            self.move_to_front(idx);
            return;
        }

        if self.size >= self.capacity {
            // Evict LRU (tail).
            if let Some(t) = self.tail {
                self.detach(t);
                let evicted_key = self.arena[t].key;
                self.map.remove(&evicted_key);
                self.free.push(t);
                self.size -= 1;
            }
        }

        // Allocate a slot (recycle from free list if possible).
        let idx = if let Some(slot) = self.free.pop() {
            let n = &mut self.arena[slot];
            n.key = key;
            n.value = value;
            n.prev = None;
            n.next = None;
            slot
        } else {
            let slot = self.arena.len();
            self.arena.push(Node {
                key,
                value,
                prev: None,
                next: None,
            });
            slot
        };

        self.map.insert(key, idx);
        self.push_front(idx);
        self.size += 1;
    }
}

#[cfg(test)]
mod tests {
    use super::*;

    // 1. put/get basic hit.
    #[test]
    fn test_put_get_basic_hit() {
        let mut c = LRUCache::new(2);
        c.put(1, 100);
        assert_eq!(c.get(1), Some(100));
    }

    // 2. get on missing key returns not-found.
    #[test]
    fn test_get_missing_returns_none() {
        let mut c = LRUCache::new(2);
        assert_eq!(c.get(42), None);
        c.put(1, 1);
        assert_eq!(c.get(2), None);
    }

    // 3. Update existing key changes value, no eviction.
    #[test]
    fn test_update_existing_no_eviction() {
        let mut c = LRUCache::new(2);
        c.put(1, 1);
        c.put(2, 2);
        c.put(1, 111); // update, must not evict 2
        assert_eq!(c.get(1), Some(111));
        assert_eq!(c.get(2), Some(2));
        assert_eq!(c.len(), 2);
    }

    // 4. Exceeding capacity evicts the LRU key.
    #[test]
    fn test_exceed_capacity_evicts_lru() {
        let mut c = LRUCache::new(2);
        c.put(1, 1);
        c.put(2, 2);
        c.put(3, 3); // evicts key 1 (LRU)
        assert_eq!(c.get(1), None);
        assert_eq!(c.get(2), Some(2));
        assert_eq!(c.get(3), Some(3));
        assert_eq!(c.len(), 2);
    }

    // 5. get() refreshes recency (the got key survives a subsequent eviction).
    #[test]
    fn test_get_refreshes_recency() {
        let mut c = LRUCache::new(2);
        c.put(1, 1);
        c.put(2, 2);
        assert_eq!(c.get(1), Some(1)); // 1 now MRU, 2 is LRU
        c.put(3, 3); // evicts 2, not 1
        assert_eq!(c.get(1), Some(1));
        assert_eq!(c.get(2), None);
        assert_eq!(c.get(3), Some(3));
    }

    // 6. Capacity 1 edge case.
    #[test]
    fn test_capacity_one() {
        let mut c = LRUCache::new(1);
        c.put(1, 1);
        assert_eq!(c.get(1), Some(1));
        c.put(2, 2); // evicts 1
        assert_eq!(c.get(1), None);
        assert_eq!(c.get(2), Some(2));
        assert_eq!(c.len(), 1);
    }

    // 7. Overwrite refreshes recency.
    #[test]
    fn test_overwrite_refreshes_recency() {
        let mut c = LRUCache::new(2);
        c.put(1, 1);
        c.put(2, 2);
        c.put(1, 10); // overwrite -> 1 becomes MRU, 2 is LRU
        c.put(3, 3); // evicts 2, not 1
        assert_eq!(c.get(1), Some(10));
        assert_eq!(c.get(2), None);
        assert_eq!(c.get(3), Some(3));
    }
}

package lru

// node is an element in the intrusive doubly linked list.
type node struct {
	key, value int64
	prev, next *node
}

// LRUCache is a fixed-capacity least-recently-used cache with int64 keys/values.
// All operations are O(1) average using a hashmap + doubly linked list.
type LRUCache struct {
	capacity int
	items    map[int64]*node
	// head is the sentinel; head.next is the most-recently-used,
	// head.prev is the least-recently-used.
	head *node
}

// NewLRUCache creates a cache with the given positive capacity.
func NewLRUCache(capacity int) *LRUCache {
	if capacity <= 0 {
		panic("lru: capacity must be > 0")
	}
	h := &node{}
	h.prev = h
	h.next = h
	return &LRUCache{
		capacity: capacity,
		items:    make(map[int64]*node, capacity),
		head:     h,
	}
}

// unlink removes n from the linked list.
func (c *LRUCache) unlink(n *node) {
	n.prev.next = n.next
	n.next.prev = n.prev
}

// pushFront inserts n right after the sentinel head (most-recently-used).
func (c *LRUCache) pushFront(n *node) {
	n.prev = c.head
	n.next = c.head.next
	c.head.next.prev = n
	c.head.next = n
}

// moveToFront marks n as most-recently-used.
func (c *LRUCache) moveToFront(n *node) {
	c.unlink(n)
	c.pushFront(n)
}

// Get returns the value for key and marks it most-recently-used.
// The second return value reports whether the key was present.
func (c *LRUCache) Get(key int64) (int64, bool) {
	n, ok := c.items[key]
	if !ok {
		return 0, false
	}
	c.moveToFront(n)
	return n.value, true
}

// Put inserts or updates key with value, marking it most-recently-used.
// Inserting a new key when at capacity evicts the least-recently-used key first.
func (c *LRUCache) Put(key, value int64) {
	if n, ok := c.items[key]; ok {
		n.value = value
		c.moveToFront(n)
		return
	}
	if len(c.items) >= c.capacity {
		// Evict least-recently-used (head.prev).
		lru := c.head.prev
		c.unlink(lru)
		delete(c.items, lru.key)
	}
	n := &node{key: key, value: value}
	c.pushFront(n)
	c.items[key] = n
}

// Len returns the number of items currently stored.
func (c *LRUCache) Len() int {
	return len(c.items)
}

import java.util.HashMap;
import java.util.OptionalLong;

/**
 * LRU cache with 64-bit long keys and values.
 *
 * Implementation: HashMap<Long,Node> + a manually-built doubly linked list.
 * (Not LinkedHashMap.) All ops are O(1) average.
 *
 * Not-found signal: get(long) returns an OptionalLong. A missing key yields
 * OptionalLong.empty(); a present key yields OptionalLong.of(value).
 * (getOrDefault(key, sentinel) is also provided for the hot benchmark path.)
 *
 * Recency: the head sentinel's next is the most-recently-used node; the tail
 * sentinel's prev is the least-recently-used node (the eviction victim).
 */
public final class LRUCache {

    private static final class Node {
        long key;
        long value;
        Node prev;
        Node next;

        Node(long key, long value) {
            this.key = key;
            this.value = value;
        }
    }

    private final int capacity;
    private final HashMap<Long, Node> map;
    private final Node head; // sentinel: head.next == MRU
    private final Node tail; // sentinel: tail.prev == LRU

    public LRUCache(int capacity) {
        if (capacity <= 0) {
            throw new IllegalArgumentException("capacity must be > 0, got " + capacity);
        }
        this.capacity = capacity;
        // Size the map to avoid rehashing during the workload.
        this.map = new HashMap<>(capacity * 2);
        this.head = new Node(0L, 0L);
        this.tail = new Node(0L, 0L);
        this.head.next = this.tail;
        this.tail.prev = this.head;
    }

    /** Unlink a node from the list. */
    private void unlink(Node n) {
        n.prev.next = n.next;
        n.next.prev = n.prev;
    }

    /** Insert a node right after head (make it MRU). */
    private void insertFront(Node n) {
        n.prev = head;
        n.next = head.next;
        head.next.prev = n;
        head.next = n;
    }

    /** Move an existing node to the front (mark MRU). */
    private void moveToFront(Node n) {
        unlink(n);
        insertFront(n);
    }

    /**
     * Return the value for key and mark it MRU, or OptionalLong.empty() if absent.
     */
    public OptionalLong get(long key) {
        Node n = map.get(key);
        if (n == null) {
            return OptionalLong.empty();
        }
        moveToFront(n);
        return OptionalLong.of(n.value);
    }

    /**
     * Hot-path variant for benchmarking: returns the value if present (marking it
     * MRU), otherwise returns the provided sentinel. Avoids OptionalLong boxing.
     */
    public long getOrDefault(long key, long sentinel) {
        Node n = map.get(key);
        if (n == null) {
            return sentinel;
        }
        moveToFront(n);
        return n.value;
    }

    /** Insert or update key->value; mark MRU; evict LRU if a new key overflows. */
    public void put(long key, long value) {
        Node existing = map.get(key);
        if (existing != null) {
            existing.value = value;
            moveToFront(existing);
            return;
        }
        if (map.size() >= capacity) {
            // Evict LRU (tail.prev).
            Node lru = tail.prev;
            unlink(lru);
            map.remove(lru.key);
        }
        Node n = new Node(key, value);
        insertFront(n);
        map.put(key, n);
    }

    /** Current number of entries. */
    public int len() {
        return map.size();
    }
}

Here's the core of each — all the same algorithm (hashmap + doubly-linked list, O(1) get/put), just expressed in each language's idiom. Boilerplate (imports, tests, benchmark harnesses) trimmed.

## C++ — `std::list::splice` for O(1) recency

```cpp
class LRUCache {
public:
    explicit LRUCache(std::size_t capacity) : capacity_(capacity) { /* >0 check */ }

    std::optional<std::int64_t> get(std::int64_t key) {
        auto it = map_.find(key);
        if (it == map_.end()) return std::nullopt;
        order_.splice(order_.begin(), order_, it->second);  // move to MRU, O(1)
        return it->second->second;
    }

    void put(std::int64_t key, std::int64_t value) {
        auto it = map_.find(key);
        if (it != map_.end()) {                       // update existing, no evict
            it->second->second = value;
            order_.splice(order_.begin(), order_, it->second);
            return;
        }
        if (map_.size() >= capacity_) {               // evict LRU first
            map_.erase(order_.back().first);
            order_.pop_back();
        }
        order_.emplace_front(key, value);
        map_.emplace(key, order_.begin());
    }
private:
    std::size_t capacity_;
    std::list<std::pair<std::int64_t,std::int64_t>> order_;   // front=MRU, back=LRU
    std::unordered_map<std::int64_t, decltype(order_)::iterator> map_;
};
```

## Python — dict + hand-rolled DLL with sentinels

```python
class LRUCache:
    def __init__(self, capacity):
        self._capacity = capacity
        self._map = {}
        self._head = _Node()   # MRU side
        self._tail = _Node()   # LRU side
        self._head.next = self._tail
        self._tail.prev = self._head

    def get(self, key):
        node = self._map.get(key)
        if node is None:
            return None
        self._move_to_front(node)
        return node.value

    def put(self, key, value):
        node = self._map.get(key)
        if node is not None:                    # update, no evict
            node.value = value
            self._move_to_front(node)
            return
        if len(self._map) >= self._capacity:    # evict LRU (before tail sentinel)
            lru = self._tail.prev
            self._remove(lru)
            del self._map[lru.key]
        node = _Node(key, value)
        self._map[key] = node
        self._add_front(node)
```

## Rust — arena-based list, 100% safe (no raw pointers)

Links are `Option<usize>` indices into a `Vec` arena, with a free list to recycle slots:

```rust
pub struct LRUCache {
    capacity: usize,
    map: HashMap<i64, usize>,
    arena: Vec<Node>,          // Node { key, value, prev: Option<usize>, next: Option<usize> }
    free: Vec<usize>,          // recycled slots
    head: Option<usize>,       // MRU
    tail: Option<usize>,       // LRU
    size: usize,
}

impl LRUCache {
    pub fn get(&mut self, key: i64) -> Option<i64> {
        if let Some(&idx) = self.map.get(&key) {
            self.move_to_front(idx);
            Some(self.arena[idx].value)
        } else { None }
    }

    pub fn put(&mut self, key: i64, value: i64) {
        if let Some(&idx) = self.map.get(&key) {          // update, no evict
            self.arena[idx].value = value;
            self.move_to_front(idx);
            return;
        }
        if self.size >= self.capacity {                   // evict tail (LRU)
            if let Some(t) = self.tail {
                self.detach(t);
                let k = self.arena[t].key;
                self.map.remove(&k);
                self.free.push(t);
                self.size -= 1;
            }
        }
        let idx = /* pop from free list or push new Node */;
        self.map.insert(key, idx);
        self.push_front(idx);
        self.size += 1;
    }
}
```

## Go — intrusive DLL with a circular sentinel

```go
type node struct {
    key, value int64
    prev, next *node
}

type LRUCache struct {
    capacity int
    items    map[int64]*node
    head     *node   // sentinel: head.next=MRU, head.prev=LRU (circular)
}

func (c *LRUCache) Get(key int64) (int64, bool) {
    n, ok := c.items[key]
    if !ok {
        return 0, false
    }
    c.moveToFront(n)
    return n.value, true
}

func (c *LRUCache) Put(key, value int64) {
    if n, ok := c.items[key]; ok {          // update, no evict
        n.value = value
        c.moveToFront(n)
        return
    }
    if len(c.items) >= c.capacity {          // evict LRU (head.prev)
        lru := c.head.prev
        c.unlink(lru)
        delete(c.items, lru.key)
    }
    n := &node{key: key, value: value}
    c.pushFront(n)
    c.items[key] = n
}
```

## Java — HashMap + DLL, `OptionalLong` for not-found

```java
public final class LRUCache {
    private final int capacity;
    private final HashMap<Long, Node> map;
    private final Node head, tail;   // sentinels: head.next=MRU, tail.prev=LRU

    public OptionalLong get(long key) {
        Node n = map.get(key);
        if (n == null) return OptionalLong.empty();
        moveToFront(n);
        return OptionalLong.of(n.value);
    }

    public void put(long key, long value) {
        Node existing = map.get(key);
        if (existing != null) {              // update, no evict
            existing.value = value;
            moveToFront(existing);
            return;
        }
        if (map.size() >= capacity) {        // evict LRU (tail.prev)
            Node lru = tail.prev;
            unlink(lru);
            map.remove(lru.key);
        }
        Node n = new Node(key, value);
        insertFront(n);
        map.put(key, n);
    }
}
```

**The through-line:** identical logic in all five — `get` = lookup + move-to-front; `put` = update-in-place or (evict-tail-if-full then insert-front). The only real design divergence is the list: C++ leans on `std::list`, Python/Go/Java hand-build a pointer-based DLL with sentinels, and Rust swaps pointers for arena indices to stay in safe code. That arena trick is also why Rust benched fastest — no per-node heap allocation.

